\nimport \'package:flutter/material.dart\';\nimport \'package:provider/provider.dart\';\nimport \'package:firebase_auth/firebase_auth.dart\';\nimport \'package:firebase_core/firebase_core.dart\';\nimport \'package:firebase_messaging/firebase_messaging.dart\';\nimport \'firebase_options.dart\';\n\nimport \'package:myapp/services/auth_service.dart\';\nimport \'package:myapp/services/firestore_service.dart\';\nimport \'package:myapp/services/download_service.dart\';\nimport \'package:myapp/services/push_notification_service.dart\';\nimport \'package:myapp/theme/theme_provider.dart\';\nimport \'package:myapp/theme/app_theme.dart\';\nimport \'package:myapp/screens/manga_screen.dart\';\nimport \'package:myapp/screens/favorites_screen.dart\';\nimport \'package:myapp/screens/history_screen.dart\';\nimport \'package:myapp/screens/downloads_screen.dart\';\nimport \'package:myapp/screens/auth_screen.dart\';\n\n// Must be a top-level function\n@pragma(\'vm:entry-point\')\nFuture<void> _firebaseMessagingBackgroundHandler(RemoteMessage message) async {\n  await Firebase.initializeApp(options: DefaultFirebaseOptions.currentPlatform);\n  print(\"Handling a background message: \${message.messageId}\");\n}\n\nvoid main() async {\n  WidgetsFlutterBinding.ensureInitialized();\n  await Firebase.initializeApp(\n    options: DefaultFirebaseOptions.currentPlatform,\n  );\n  FirebaseMessaging.onBackgroundMessage(_firebaseMessagingBackgroundHandler);\n\n  runApp(\n    MultiProvider(\n      providers: [\n        ChangeNotifierProvider(create: (context) => ThemeProvider()),\n        Provider<AuthService>(create: (_) => AuthService()),\n        Provider<FirestoreService>(create: (_) => FirestoreService()),\n        Provider<DownloadService>(create: (_) => DownloadService.instance),\n        ProxyProvider<FirestoreService, PushNotificationService>(\n          update: (context, firestoreService, previous) => \n              PushNotificationService(firestoreService),\n        ),\n      ],\n      child: const MyApp(),\n    ),\n  );\n}\n\nclass MyApp extends StatelessWidget {\n  const MyApp({super.key});\n\n  @override\n  Widget build(BuildContext context) {\n    return Consumer<ThemeProvider>(\n      builder: (context, themeProvider, child) {\n        return MaterialApp(\n          title: \'Manga Reader\',\n          theme: AppTheme.lightTheme,\n          darkTheme: AppTheme.darkTheme,\n          themeMode: themeProvider.themeMode,\n          home: const AuthWrapper(),\n          debugShowCheckedModeBanner: false,\n        );\n      },\n    );\n  }\n}\n\nclass AuthWrapper extends StatelessWidget {\n  const AuthWrapper({super.key});\n\n  @override\n  Widget build(BuildContext context) {\n    return StreamBuilder<User?>(\n      stream: context.watch<AuthService>().user,\n      builder: (context, snapshot) {\n        if (snapshot.connectionState == ConnectionState.active) {\n          return snapshot.data == null ? const AuthScreen() : const HomePage();\n        } else {\n          return const Scaffold(\n            body: Center(child: CircularProgressIndicator()),\n          );\n        }\n      },\n    );\n  }\n}\n\nclass HomePage extends StatefulWidget {\n  const HomePage({super.key});\n\n  @override\n  HomePageState createState() => HomePageState();\n}\n\nclass HomePageState extends State<HomePage> {\n  int _selectedIndex = 0;\n\n  @override\n  void initState() {\n    super.initState();\n    // Initialize notification service once the user is logged in and home page is shown.\n    Provider.of<PushNotificationService>(context, listen: false).initialize();\n  }\n\n\n  static const List<Widget> _widgetOptions = <Widget>[\n    MangaScreen(),\n    FavoritesScreen(),\n    HistoryScreen(),\n    DownloadsScreen(),\n  ];\n\n  static const List<String> _titles = <String>[\n    \'Home\',\n    \'Favorites\',\n    \'History\',\n    \'Downloads\',\n  ];\n\n  void _onItemTapped(int index) {\n    setState(() {\n      _selectedIndex = index;\n    });\n  }\n\n  @override\n  Widget build(BuildContext context) {\n    final authService = Provider.of<AuthService>(context, listen: false);\n    return Scaffold(\n      appBar: AppBar(\n        title: Text(_titles[_selectedIndex]),\n        actions: [\n          IconButton(\n            icon: const Icon(Icons.logout),\n            onPressed: () => authService.signOut(),\n            tooltip: \'Sign Out\',\n          ),\n          IconButton(\n            icon: const Icon(Icons.brightness_6),\n            onPressed: () => Provider.of<ThemeProvider>(context, listen: false).toggleTheme(),\n            tooltip: \'Toggle Theme\',\n          ),\n        ],\n      ),\n      body: IndexedStack(\n        index: _selectedIndex,\n        children: _widgetOptions,\n      ),\n      bottomNavigationBar: BottomNavigationBar(\n        type: BottomNavigationBarType.fixed,\n        items: const <BottomNavigationBarItem>[\n          BottomNavigationBarItem(icon: Icon(Icons.home), label: \'Home\'),\n          BottomNavigationBarItem(icon: Icon(Icons.favorite), label: \'Favorites\'),\n          BottomNavigationBarItem(icon: Icon(Icons.history), label: \'History\'),\n          BottomNavigationBarItem(icon: Icon(Icons.download), label: \'Downloads\'),\n        ],\n        currentIndex: _selectedIndex,\n        onTap: _onItemTapped,\n      ),\n    );\n  }\n}\n